'use strict';
const CONFIG={url:'https://zfqnomvcnxzkwfxasuij.supabase.co',key:'sb_publishable_J7xVB3foL3WuWj2U0gD8bQ_rJD6eGKH'};
const key='optimind-admin-session'; let session=null,member=null,currentStore=null,categories=[],products=[],availableStores=[];
const $=(s,p=document)=>p.querySelector(s); const $$=(s,p=document)=>[...p.querySelectorAll(s)];
function note(message){const el=$('[data-notice]');el.hidden=!message;el.textContent=message||''}
function escapeHtml(value){return String(value??'').replace(/[&<>'"]/g,character=>({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[character]))}
function headers(extra={}){return {'apikey':CONFIG.key,'Authorization':`Bearer ${session.access_token}`,'Content-Type':'application/json','Prefer':'return=representation',...extra}}
async function api(path,options={}){const res=await fetch(`${CONFIG.url}/rest/v1/${path}`,{...options,headers:headers(options.headers)});if(!res.ok){const body=await res.text();throw new Error(body||'No se pudo completar la acción.')}return res.status===204?null:res.json()}
function slugify(value){return value.normalize('NFD').replace(/[\u0300-\u036f]/g,'').toLowerCase().trim().replace(/[^a-z0-9]+/g,'-').replace(/(^-|-$)/g,'')}
function saveSession(value){session=value;localStorage.setItem(key,JSON.stringify(value))}
function loadHash(){const params=new URLSearchParams(location.hash.slice(1));if(params.get('access_token')){saveSession({access_token:params.get('access_token'),refresh_token:params.get('refresh_token'),expires_at:Date.now()+Number(params.get('expires_in')||3600)*1000});history.replaceState({},'',location.pathname)}}
async function login(email){const r=await fetch(`${CONFIG.url}/auth/v1/otp`,{method:'POST',headers:{apikey:CONFIG.key,'Content-Type':'application/json'},body:JSON.stringify({email,create_user:true,email_redirect_to:`${location.origin}${location.pathname}`})});if(!r.ok)throw new Error('No se pudo enviar el enlace. Revisá el email e intentá de nuevo.')}
async function getUser(){const r=await fetch(`${CONFIG.url}/auth/v1/user`,{headers:headers()});if(!r.ok)throw new Error('Tu sesión venció. Pedí un nuevo enlace.');return r.json()}
async function loadMembership(user){const rows=await api(`store_members?user_id=eq.${encodeURIComponent(user.id)}&select=store_id,role,stores(id,slug,name,plan,is_active)`);if(!rows.length)throw new Error('Tu cuenta existe, pero todavía no tiene acceso a una tienda.');member=rows.find(row=>row.role==='platform_admin')||rows[0];availableStores=rows.map(row=>({...row.stores,role:row.role}));if(member.role==='platform_admin'){availableStores=(await api('stores?is_active=eq.true&select=id,slug,name,plan,is_active&order=created_at.asc')).map(store=>({...store,role:'platform_admin'}))}currentStore=availableStores[0];const select=$('[data-store-select]');select.innerHTML=availableStores.map(store=>`<option value="${store.id}">${escapeHtml(store.name)}</option>`).join('');select.value=currentStore.id;select.disabled=member.role!=='platform_admin'||availableStores.length<2;$('[data-role-label]').textContent=member.role==='platform_admin'?'Administración OptiMind':'Panel de tienda';$('[data-store-name]').textContent=currentStore.name;return availableStores}
async function loadData(){if(!currentStore)return;[categories,products]=await Promise.all([api(`categories?store_id=eq.${currentStore.id}&select=*&order=position.asc`),api(`products?store_id=eq.${currentStore.id}&select=*&order=position.asc`)]);render()}
function render(){const visible=products.filter(p=>p.is_published).length;$('[data-overview-title]').textContent=currentStore.name;$('[data-overview-copy]').textContent=`${products.length} productos administrados desde una única base segura.`;$('[data-metrics]').innerHTML=[['Productos',products.length],['Publicados',visible],['Categorías',categories.length]].map(([label,count])=>`<article class="metric"><small>${label}</small><b>${count}</b></article>`).join('');$('[data-activity]').textContent='';$('[data-product-list]').innerHTML=products.length?products.map(product=>`<article class="product"><div><b>${escapeHtml(product.name)}</b><small>${product.is_published?'Publicado':'Borrador'} · ${product.category_id?'Con categoría':'Sin categoría'}</small></div><strong>$ ${Number(product.price).toLocaleString('es-AR')}</strong></article>`).join(''):'<p class="empty">Todavía no hay productos. Creá el primero a la derecha.</p>';$('[data-category-select]').innerHTML=`<option value="">Sin categoría</option>${categories.map(category=>`<option value="${category.id}">${escapeHtml(category.name)}</option>`).join('')}`;loadOrders()}
async function loadOrders(){try{const rows=await api(`orders?store_id=eq.${currentStore.id}&select=order_number,status,total,created_at&order=created_at.desc&limit=12`);$('[data-orders]').innerHTML=rows.length?rows.map(order=>`<article class="order"><div><b>Pedido #${escapeHtml(order.order_number)}</b><small>${new Date(order.created_at).toLocaleString('es-AR')} · ${escapeHtml(order.status)}</small></div><strong>$ ${Number(order.total||0).toLocaleString('es-AR')}</strong></article>`).join(''):'<p class="empty">Los tickets enviados a WhatsApp aparecerán acá.</p>'}catch{ $('[data-orders]').innerHTML='<p class="empty">Todavía no hay pedidos para esta tienda.</p>'}}
function showWorkspace(){ $('#auth-view').hidden=true;$('#workspace').hidden=false }
async function start(){loadHash();try{session=JSON.parse(localStorage.getItem(key)||'null');if(!session)throw new Error('');const user=await getUser();await loadMembership(user);showWorkspace();await loadData()}catch(error){session=null;localStorage.removeItem(key);$('#auth-view').hidden=false;$('#workspace').hidden=true;if(error.message)note('')}}
$('[data-login-form]').addEventListener('submit',async e=>{e.preventDefault();const form=e.currentTarget,button=$('button',form);button.disabled=true;try{await login(new FormData(form).get('email'));$('[data-auth-note]').textContent='Te enviamos un enlace. Abrilo en este mismo dispositivo para entrar.'}catch(error){$('[data-auth-note]').textContent=error.message}finally{button.disabled=false}});
$$('.nav').forEach(button=>button.addEventListener('click',()=>{ $$('.nav').forEach(x=>x.classList.toggle('is-active',x===button));$$('[data-panel]').forEach(x=>x.hidden=x.dataset.panel!==button.dataset.tab);$('[data-heading]').textContent=button.textContent}));
$('[data-store-select]').addEventListener('change',async event=>{const id=event.target.value;const nextStore=availableStores.find(store=>store.id===id);if(!nextStore)return;currentStore=nextStore;$('[data-store-name]').textContent=currentStore.name;await loadData()});
$$('[data-refresh]').forEach(b=>b.addEventListener('click',()=>loadData().catch(e=>note(e.message))));
$('[data-category-form]').addEventListener('submit',async e=>{e.preventDefault();try{const name=new FormData(e.currentTarget).get('name').trim();await api('categories',{method:'POST',body:JSON.stringify({store_id:currentStore.id,name,slug:slugify(name),position:categories.length*10,is_visible:true})});e.currentTarget.reset();await loadData();note('Categoría creada.')}catch(err){note(err.message)}});
$('[data-product-form]').addEventListener('submit',async e=>{e.preventDefault();try{const d=new FormData(e.currentTarget),name=d.get('name').trim();await api('products',{method:'POST',body:JSON.stringify({store_id:currentStore.id,category_id:d.get('category_id')||null,name,slug:slugify(name),price:Number(d.get('price')),is_published:d.get('is_published')==='on',position:products.length*10,metadata:{stock_status:'in_stock'}})});e.currentTarget.reset();await loadData();note('Producto creado.')}catch(err){note(err.message)}});
$('[data-signout]').addEventListener('click',()=>{localStorage.removeItem(key);location.reload()});start();
